/* Combined custom JS: publicf9e3.js + index-init.js (lightly minified) */
(function($){
$(document).ready(function(){
    $(".navBtnA").click(function(){
        $(".nav_box ul li .suv").stop().slideUp();
        $(".nav_box ul li .sbmd").removeClass("cur");
        $(".nav_box ul li .sbdm .sum").stop().slideUp();
        $(".nav_box ul li .sbdm").removeClass("cur");
    });
    $(document).on("click",".navBtn",function(){
        $(".nav_box_6").toggleClass("cur");
        $(".header").toggleClass("cur");
    });
    $(".navBtn").click(function(e){
        $(".nav_box").toggleClass("cur");
        $(this).toggleClass("mobile-menu-on");
        $(this).toggleClass("navBtnA");
        $(".nav_box .navlist ul>li .navlist2").css("left","-102%");
        $(".nav_box .navlist ul>li").removeClass("cur");
        e.stopPropagation();
    });
    $(".backFirst").click(function(){ $(".nav_box .navlist ul>li .navlist2").css("left","-102%"); });
    $(document).on("click",".nav_box .navlist ul>li .navlist2 a",function(){ $(".navBtn").removeClass("mobile-menu-on"); });
    $(document).on("click",".nav_box .navlist ul>li a.sub",function(){ $(this).next().css("left","0"); });
    $(".nav_box .navlist ul>li .sub").click(function(){ $(this).toggleClass("cur"); $(this).next(".navlist4").find(".nomsjkxks").slideToggle(400); });
    var headerH=$(".header").outerHeight()||80; $(window).scroll(function(){ var s=$(document).scrollTop(); if(s>headerH){ $(".header").addClass("fixed-head"); } else { $(".header").removeClass("fixed-head"); } });
    $(".nybanner").addClass("cur"); $(".commonbanner").addClass("cur");
    $(".tabSwitch").each(function(){ var obj=$(this); obj.find(".tabTit").children().on("click tab",function(){ $(this).addClass("cur").siblings().removeClass("cur"); if($(this).data("to")){ $($(this).data("to")).val($(this).data("id")); } if(obj.find(".tabBox").children().eq($(this).index()).length>0) obj.find(".tabBox").children().hide().eq($(this).index()).show(); if(obj.find(".tabBox2").children().eq($(this).index()).length>0) obj.find(".tabBox2").children().hide().eq($(this).index()).show(); return false; }); obj.find(".tabTit .cur").trigger("tab"); });
    $(".tabSwitchHover").each(function(){ var obj=$(this); obj.find(".tabTit").children().on("mouseover tab",function(){ $(this).addClass("cur").siblings().removeClass("cur"); if($(this).data("to")){ $($(this).data("to")).val($(this).data("id")); } if(obj.find(".tabBox").children().eq($(this).index()).length>0) obj.find(".tabBox").children().hide().eq($(this).index()).show(); if(obj.find(".tabBox2").children().eq($(this).index()).length>0) obj.find(".tabBox2").children().hide().eq($(this).index()).show(); }); obj.find(".tabTit .cur").trigger("tab"); });
    $(".backTop").click(function(){ if($(document).scrollTop()!==0){ $("html,body").animate({scrollTop:0},500); } });
    $("body").addClass("hide");
    var currentPage=window.location.pathname.split("/").pop()||"index.html"; $(".header-r1 ul li a").each(function(){ var href=$(this).attr("href"); if(href===currentPage){ $(this).addClass("active-link"); $(this).closest("li").addClass("active"); } }); $(".nav_box .navlist ul li a").each(function(){ var href=$(this).attr("href"); if(href===currentPage){ $(this).addClass("active-link"); } });
});
})(jQuery);

/* Block scroll when mobile menu open */
(function(){
var navElement=document.querySelector(".nav_box_6.nav_box"); if(!navElement) return; var preventScroll=function(e){ e.preventDefault(); };
var observer=new MutationObserver(function(mutations){ mutations.forEach(function(mutation){ if(mutation.attributeName!="class") return; if(navElement.classList.contains("cur")){ document.body.style.overflow="hidden"; document.addEventListener("touchmove",preventScroll,{passive:false}); document.addEventListener("wheel",preventScroll,{passive:false}); } else { document.body.style.overflow="auto"; document.removeEventListener("touchmove",preventScroll); document.removeEventListener("wheel",preventScroll); } }); });
observer.observe(navElement,{attributes:true,attributeFilter:["class"]});
})();

/* Show/hide backTop and banner effect */
window.addEventListener('scroll',function(){ var s=document.documentElement.scrollTop||document.body.scrollTop; if(s>400){ var el=document.querySelectorAll('.backTop'); el.forEach(function(x){ $(x).fadeIn(); }); } else { var el=document.querySelectorAll('.backTop'); el.forEach(function(x){ $(x).fadeOut(); }); } if(document.querySelector('.nybanner') && s>document.querySelector('.nybanner').clientHeight){ document.querySelector('.mbdaoh') && document.querySelector('.mbdaoh').classList.add('owoe'); } else { document.querySelector('.mbdaoh') && document.querySelector('.mbdaoh').classList.remove('owoe'); } });

/* Index initializations (swiper, wow, parallax) */
(function(){ 'use strict'; new WOW().init(); var swiperBanner=new Swiper('.indexbanner .swiper-container',{speed:800,navigation:{nextEl:'.indexbanner .swiper-button-next',prevEl:'.indexbanner .swiper-button-prev'},pagination:{el:'.indexbanner .swiper-pagination',clickable:true},autoplay:{delay:5000,disableOnInteraction:false},on:{init:function(){ $('.indexbanner .swiper-pagination .swiper-pagination-bullet-active').addClass('cur').siblings().removeClass('cur'); },slideChangeTransitionEnd:function(){ $('.indexbanner .swiper-pagination .swiper-pagination-bullet-active').addClass('cur').siblings().removeClass('cur'); }}});
window.addEventListener('scroll',function(){ var npos=window.scrollY||document.documentElement.scrollTop; var SH=window.innerHeight; var SW=window.innerWidth; var $subject=$('.subject'); if($subject.length){ var subjectOffset=$subject.offset(); if(subjectOffset){ var mHei=subjectOffset.top; var TextHei=$subject.height(); if(TextHei>0){ if(npos>(mHei-SH*0.5)){ var num=((npos-mHei+SH*0.5)/TextHei)*80; if(num<=0) num=0; else if(num>100) num=100; $('.subject .t1').css('background-size',num+'% 100%'); } else { $('.subject .t1').css('background-size','0% 100%'); } } } }
var $addCase=$('.addCaseC-c'); if($addCase.length){ var addCaseOffset=$addCase.offset(); if(addCaseOffset){ var mHei2=addCaseOffset.top; if(npos>(mHei2-SH*0.5)){ var wyHei=(npos-mHei2+SH*0.5)*0.6; var wyHeib=wyHei-260; if(SW<1100){ wyHeib=wyHeib*0.5; } $('.subject').css('bottom',wyHeib+'px'); } } } });
var swiperB=new Swiper('.indexB .indexb-top .swiper-container',{speed:800,spaceBetween:150,autoplay:{delay:5000,disableOnInteraction:false},on:{init:function(swiper){ var activeIndex=swiper.activeIndex; $('.indexb-bottom li').eq(activeIndex).addClass('cur').siblings().removeClass('cur'); },slideChangeTransitionEnd:function(){ var activeIndex=this.activeIndex; $('.indexb-bottom li').eq(activeIndex).addClass('cur').siblings().removeClass('cur'); }}});
$('.indexb-bottom').on('click','li',function(){ var index=$(this).index(); swiperB.slideTo(index,800); $(this).addClass('cur').siblings().removeClass('cur'); }); $('body').addClass('hide'); var swiperE=new Swiper('.indexE .swiper-container',{speed:800,slidesPerView:1,spaceBetween:10,navigation:{nextEl:'.indexE .swiper-button-next',prevEl:'.indexE .swiper-button-prev'},breakpoints:{1101:{slidesPerView:3,spaceBetween:10}}}); var swiperA1=new Swiper('.two-a1',{loop:true,speed:80000,simulateTouch:false,slidesPerView:1,freeMode:true,spaceBetween:0,slidesPerGroup:1,grabCursor:true,autoplay:{delay:1,disableOnInteraction:false}}); var swiperA2=new Swiper('.two-a2',{loop:true,speed:80000,simulateTouch:false,slidesPerView:1,freeMode:true,spaceBetween:0,slidesPerGroup:1,grabCursor:true,autoplay:{delay:1,disableOnInteraction:false,reverseDirection:true}});
document.addEventListener('DOMContentLoaded',function(){ var slides=document.querySelectorAll('.indexbanner .swiper-slide'); var maxHeight=0; slides.forEach(function(slide){ var height=slide.offsetHeight; if(height>maxHeight) maxHeight=height; }); slides.forEach(function(slide){ slide.style.height=maxHeight+'px'; }); }); function setMaxHeight(){ var slides=document.querySelectorAll('.indexE .indexe-bottom .swiper-container .swiper-slide a'); var maxHeight=0; slides.forEach(function(slide){ var height=slide.offsetHeight; if(height>maxHeight) maxHeight=height; }); slides.forEach(function(slide){ slide.style.height=maxHeight+'px'; }); } document.addEventListener('DOMContentLoaded',setMaxHeight); window.addEventListener('resize',setMaxHeight);
})();
